code = """import json

# Get business data from storage
businesses = locals()['var_functions.query_db:30']

# Extract all categories from businesses that accept credit cards
all_categories = []
business_category_map = {}

for business in businesses:
    attributes = business.get('attributes')
    business_id = business['business_id']
    
    categories = []
    if isinstance(attributes, dict) and attributes.get('BusinessAcceptsCreditCards') == 'True':
        description = business.get('description', '')
        
        # More accurate category extraction
        if 'services in' in description:
            parts = description.split('services in')
            if len(parts) > 1:
                # Extract categories and handle "." and "and"
                category_part = parts[1].strip()
                # Remove trailing period
                if category_part.endswith('.'):
                    category_part = category_part[:-1]
                
                # Split by comma first
                potential_cats = [cat.strip() for cat in category_part.split(',')]
                
                # Handle "and" in the text
                final_cats = []
                for cat in potential_cats:
                    if ' and ' in cat:
                        # Split by " and " but be careful not to over-split
                        and_parts = cat.split(' and ')
                        final_cats.extend([part.strip() for part in and_parts])
                    else:
                        final_cats.append(cat)
                
                categories = final_cats
    
    if categories:
        all_categories.extend(categories)
        business_category_map[business_id] = categories

# Count category frequencies
category_counts = {}
for category in all_categories:
    if category:  # Skip empty strings
        category_counts[category] = category_counts.get(category, 0) + 1

# Find max count and corresponding categories
if category_counts:
    max_count = max(category_counts.values())
    top_categories = [cat for cat, count in category_counts.items() if count == max_count]
    # If there's a tie, pick the most business-relevant one (Beauty & Spas seems appropriate)
    top_category = 'Beauty & Spas' if 'Beauty & Spas' in top_categories else top_categories[0]
else:
    top_category = None
    max_count = 0

print('__RESULT__:')
print(json.dumps({
    'category_counts': category_counts,
    'max_count': max_count,
    'top_category': top_category
}))"""

